DECLARE @ver INT;
DECLARE @cpu_count INT;
DECLARE @file_count INT;
DECLARE @recommended INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @cpu_count = cpu_count FROM sys.dm_os_sys_info;

SELECT @file_count = COUNT(*)
FROM sys.master_files
WHERE database_id = 2 AND type_desc = 'ROWS';

IF @cpu_count <= 8
    SET @recommended = @cpu_count;
ELSE
    SET @recommended = 8;

IF @file_count >= @recommended
BEGIN
    SET @result = 'PASS';
    SET @msg = 'TempDB has ' + CONVERT(VARCHAR, @file_count)
        + ' data file(s). Recommended minimum: ' + CONVERT(VARCHAR, @recommended)
        + ' (based on ' + CONVERT(VARCHAR, @cpu_count) + ' CPU cores).';
END
ELSE IF @file_count >= 4
BEGIN
    SET @result = 'WARN';
    SET @msg = 'TempDB has ' + CONVERT(VARCHAR, @file_count)
        + ' data file(s). Recommended: ' + CONVERT(VARCHAR, @recommended)
        + ' (based on ' + CONVERT(VARCHAR, @cpu_count) + ' CPU cores).';
END
ELSE
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'TempDB has ' + CONVERT(VARCHAR, @file_count)
        + ' data file(s). Recommended: ' + CONVERT(VARCHAR, @recommended)
        + ' (based on ' + CONVERT(VARCHAR, @cpu_count) + ' CPU cores). '
        + 'Add more files to reduce allocation contention.';
END;

