DECLARE @sa_name SYSNAME, @is_disabled BIT, @is_renamed BIT;
DECLARE @result VARCHAR(10), @msg NVARCHAR(1000);

SELECT @sa_name = name, @is_disabled = is_disabled
FROM sys.server_principals
WHERE principal_id = 1;

SET @is_renamed = CASE WHEN @sa_name <> 'sa' THEN 1 ELSE 0 END;

IF @is_disabled = 1 AND @is_renamed = 1
BEGIN
    SET @result = 'PASS';
    SET @msg = CONCAT('sa principal is disabled and renamed to [', @sa_name, ']. Hardened against name-based brute-force attacks.');
END
ELSE IF @is_disabled = 1
BEGIN
    SET @result = 'WARN';
    SET @msg = 'sa is disabled, which mitigates exploit risk. Consider also renaming for defence-in-depth (CIS recommends both).';
END
ELSE IF @is_renamed = 1
BEGIN
    SET @result = 'WARN';
    SET @msg = CONCAT('sa is renamed to [', @sa_name, '] but remains enabled. Disable the renamed principal unless a documented business case requires it.');
END
ELSE
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'sa is enabled and using the default name. This is the single most-attacked SQL Server login. Disable or rename per CIS, NIST, and STIG guidance.';
END

SELECT @result AS result, @msg AS message;

