DECLARE @windows_only INT, @sql_login_count INT, @enabled_sql_login_count INT;
DECLARE @result VARCHAR(10), @msg NVARCHAR(1000);

SET @windows_only = CONVERT(INT, SERVERPROPERTY('IsIntegratedSecurityOnly'));

SELECT
    @sql_login_count = COUNT(*),
    @enabled_sql_login_count = SUM(CASE WHEN is_disabled = 0 THEN 1 ELSE 0 END)
FROM sys.sql_logins
WHERE name NOT LIKE '##%';

IF @windows_only = 1
BEGIN
    SET @result = 'PASS';
    SET @msg = CONCAT('Server runs in Windows Authentication mode. ', @sql_login_count, ' SQL login(s) defined but cannot authenticate. Consistent with CIS, STIG, and NIST guidance.');
END
ELSE IF @enabled_sql_login_count = 0
BEGIN
    SET @result = 'WARN';
    SET @msg = CONCAT('Mixed mode is enabled but no SQL logins are active (', @sql_login_count, ' defined, all disabled). Switch to Windows-only mode to prevent re-enable risk.');
END
ELSE IF @enabled_sql_login_count <= 2
BEGIN
    SET @result = 'WARN';
    SET @msg = CONCAT('Mixed mode is enabled with ', @enabled_sql_login_count, ' active SQL login(s). Document the business need for each, then plan migration to Windows authentication.');
END
ELSE
BEGIN
    SET @result = 'FAIL';
    SET @msg = CONCAT('Mixed mode is enabled with ', @enabled_sql_login_count, ' active SQL login(s). SQL logins bypass AD policies for password complexity, lockout, and rotation. Migrate to Windows authentication where possible.');
END

SELECT @result AS result, @msg AS message;

DECLARE @ver INT;
DECLARE @total_mem_mb DECIMAL(18,2);
DECLARE @avail_mem_mb DECIMAL(18,2);
DECLARE @current_max_mb BIGINT;
DECLARE @current_min_mb BIGINT;
DECLARE @rec_msft_mb BIGINT;
DECLARE @rec_brent_mb BIGINT;
DECLARE @dev_pct DECIMAL(10,2);
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

-- Get total and available physical memory from DMV (available since SQL 2008)
SELECT @total_mem_mb = CONVERT(DECIMAL(18,2), total_physical_memory_kb / 1024.0),
       @avail_mem_mb = CONVERT(DECIMAL(18,2), available_physical_memory_kb / 1024.0)
FROM sys.dm_os_sys_memory;

-- Get current max and min server memory configuration values
SELECT @current_max_mb = CONVERT(BIGINT, MAX(CASE WHEN name = 'max server memory (MB)' THEN value_in_use ELSE 0 END)),
       @current_min_mb = CONVERT(BIGINT, MAX(CASE WHEN name = 'min server memory (MB)' THEN value_in_use ELSE 0 END))
FROM sys.configurations
WHERE name IN ('max server memory (MB)', 'min server memory (MB)');

-- Microsoft recommendation: 75% of available system memory
SET @rec_msft_mb = CONVERT(BIGINT,
    CASE WHEN @avail_mem_mb > 0 THEN ROUND(0.75 * @avail_mem_mb, 0)
         ELSE ROUND(0.75 * @total_mem_mb, 0) END);

-- Brent Ozar recommendation: total RAM - max(4 GB, 10% of total RAM)
SET @rec_brent_mb = CONVERT(BIGINT,
    @total_mem_mb - CASE WHEN (0.10 * @total_mem_mb) > (4 * 1024)
                         THEN (0.10 * @total_mem_mb) ELSE (4 * 1024) END);

-- Enforce minimum of 128 MB per Microsoft documentation
IF @rec_msft_mb < 128 SET @rec_msft_mb = 128;
IF @rec_brent_mb < 128 SET @rec_brent_mb = 128;

-- Determine result and build message
IF @current_max_mb = 2147483647
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'Max server memory is at default (2147483647 MB) - not configured. '
        + 'Use sp configure to set max server memory to the recommended value, then run reconfigure.';
END
ELSE
BEGIN
    -- Calculate deviation from Brent Ozar recommendation (more conservative of the two)
    SET @dev_pct = CASE WHEN @rec_brent_mb > 0
        THEN ABS((CONVERT(DECIMAL(18,2), @current_max_mb) - CONVERT(DECIMAL(18,2), @rec_brent_mb))
            * 100.0 / CONVERT(DECIMAL(18,2), @rec_brent_mb))
        ELSE 100 END;

    -- Check min server memory
    IF @current_min_mb != 0
    BEGIN
        SET @result = 'FAIL';
        SET @msg = 'Min server memory should be 0 (currently '
            + CONVERT(VARCHAR, @current_min_mb) + ' MB). ';
    END
    ELSE IF @dev_pct > 25
        SET @result = 'FAIL';
    ELSE IF @dev_pct > 10
        SET @result = 'WARN';
    ELSE
        SET @result = 'PASS';

    SET @msg = @msg + 'Current max: ' + CONVERT(VARCHAR, @current_max_mb) + ' MB. '
        + 'Total physical: ' + CONVERT(VARCHAR, CONVERT(BIGINT, @total_mem_mb)) + ' MB. '
        + 'Available: ' + CONVERT(VARCHAR, CONVERT(BIGINT, @avail_mem_mb)) + ' MB. '
        + 'Microsoft rec: ' + CONVERT(VARCHAR, @rec_msft_mb) + ' MB (75% of available). '
        + 'Brent Ozar rec: ' + CONVERT(VARCHAR, @rec_brent_mb) + ' MB (leave 4 GB or 10%). '
        + 'Deviation: ' + CONVERT(VARCHAR, CONVERT(INT, @dev_pct)) + '%.';
END;

SELECT @result AS result, @msg AS message;

DECLARE @ver INT, @rare_used INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result, CONCAT('Requires SQL Server 2008 (10.0) or later. Current: ',@ver) AS message; RETURN; END;
SELECT @rare_used = COUNT(*) FROM sys.indexes i LEFT JOIN sys.dm_db_index_usage_stats ius ON i.object_id = ius.object_id AND i.index_id = ius.index_id AND ius.database_id = DB_ID() WHERE i.object_id > 100 AND i.index_id > 0 AND i.is_disabled = 0 AND (ius.user_seeks + ius.user_scans + ius.user_lookups < 100 OR ius.user_seeks IS NULL);
IF @rare_used = 0 BEGIN SET @result = 'PASS'; SET @msg = 'All indexes are actively used for reads.'; END
ELSE BEGIN SET @result = 'WARN'; SET @msg = CONCAT(@rare_used,' index(es) have fewer than 100 reads. Review and consider removal to reduce write overhead.'); END
SELECT @result AS result, @msg AS message;

