SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result, CONCAT('Requires SQL Server 2008 (10.0) or later. Current: ',@ver) AS message; RETURN; END;
SELECT @sqlserver_start = sqlserver_start_time FROM sys.dm_os_sys_info;
SELECT @plan_count = COUNT(*) FROM sys.dm_exec_cached_plans;
IF @plan_count > 0 AND @sqlserver_start > DATEADD(HOUR, -1, GETDATE())
BEGIN SET @result = 'INFO'; SET @msg = CONCAT('SQL Server started ',(DATEDIFF(MINUTE,@sqlserver_start,GETDATE())),' minutes ago with ',@plan_count,' cached plans.'); END
ELSE IF @plan_count = 0 AND @sqlserver_start > DATEADD(HOUR, -1, GETDATE())
BEGIN SET @result = 'INFO'; SET @msg = 'Server started recently. Plan cache may be empty.'; END
ELSE
BEGIN SET @result = 'INFO'; SET @msg = CONCAT('Server is up ',(DATEDIFF(HOUR,@sqlserver_start,GETDATE())),' hours with ',@plan_count,' cached plans.'); END
SELECT @result AS result, @msg AS message;

