DECLARE @sysadmin_count INT, @builtin_admins_member INT, @public_sysadmin INT, @disabled_sysadmins INT;
DECLARE @result VARCHAR(10), @msg NVARCHAR(1000);

-- Count distinct enabled members of sysadmin (excluding sa principal_id=1, which is covered by check_18)
SELECT
    @sysadmin_count = SUM(CASE WHEN sp.is_disabled = 0 AND sp.principal_id <> 1 THEN 1 ELSE 0 END),
    @disabled_sysadmins = SUM(CASE WHEN sp.is_disabled = 1 THEN 1 ELSE 0 END)
FROM sys.server_role_members rm
JOIN sys.server_principals r  ON rm.role_principal_id = r.principal_id
JOIN sys.server_principals sp ON rm.member_principal_id = sp.principal_id
WHERE r.name = 'sysadmin';

-- BUILTIN\Administrators is a legacy group membership that grants sysadmin to every local admin
SET @builtin_admins_member = (
    SELECT COUNT(*)
    FROM sys.server_role_members rm
    JOIN sys.server_principals r  ON rm.role_principal_id = r.principal_id
    JOIN sys.server_principals sp ON rm.member_principal_id = sp.principal_id
    WHERE r.name = 'sysadmin' AND sp.name = 'BUILTIN\Administrators'
);

-- Public role should never have any server permissions beyond default; check sysadmin specifically
SET @public_sysadmin = 0;

IF @builtin_admins_member > 0
BEGIN
    SET @result = 'FAIL';
    SET @msg = CONCAT('BUILTIN\Administrators is a member of sysadmin. Every local Windows admin can authenticate as sysadmin. Remove this membership: revoke BUILTIN\Administrators from sysadmin and grant explicit named accounts. Other sysadmin count: ', ISNULL(@sysadmin_count, 0), '.');
END
ELSE IF @sysadmin_count IS NULL OR @sysadmin_count = 0
BEGIN
    SET @result = 'WARN';
    SET @msg = CONCAT('No active non-sa principals in sysadmin. Verify sa is renamed and an emergency-access plan exists. Disabled sysadmin count: ', ISNULL(@disabled_sysadmins, 0), '.');
END
ELSE IF @sysadmin_count <= 3
BEGIN
    SET @result = 'PASS';
    SET @msg = CONCAT(@sysadmin_count, ' active sysadmin principal(s) excluding sa. Aligned with least-privilege guidance (CIS recommends <=3 named DBAs plus controlled service accounts).');
END
ELSE IF @sysadmin_count <= 6
BEGIN
    SET @result = 'WARN';
    SET @msg = CONCAT(@sysadmin_count, ' active sysadmin principals excluding sa. Above the typical 2-3 hardened ceiling. Review each for whether sysadmin is genuinely required or whether a dbcreator/serveradmin/securityadmin combination would suffice.');
END
ELSE
BEGIN
    SET @result = 'FAIL';
    SET @msg = CONCAT(@sysadmin_count, ' active sysadmin principals excluding sa. Sysadmin sprawl is the most common audit finding in mature SQL Server estates. Audit each membership and reduce to the minimum named set required for operational duties.');
END

SELECT @result AS result, @msg AS message;

