BEGIN
    SET @result = 'PASS';
    SET @msg = CONVERT(VARCHAR, @tde_count) + ' user database(s) have TDE enabled (encryption_state = 3).';
END
ELSE
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'No user databases have TDE enabled. Consider enabling TDE for sensitive data-at-rest protection.';
END;

