SELECT @no_backup=COUNT(*) FROM sys.databases d WHERE d.database_id>4 AND d.state=0 AND NOT EXISTS(SELECT 1 FROM msdb.dbo.backupset b WHERE b.database_name=d.name AND b.type='D' AND b.backup_finish_date>DATEADD(DAY,-7,GETDATE()));
SELECT CASE WHEN @no_backup=0 THEN 'PASS' ELSE 'FAIL' END AS result, CASE WHEN @no_backup=0 THEN 'All databases have recent full backups.' ELSE CONCAT(@no_backup,' database(s) lack a full backup in the last 7 days.') END AS message;

DECLARE @ver INT, @bad INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver=CONVERT(INT,SERVERPROPERTY('ProductMajorVersion')); IF @ver<10 BEGIN SELECT 'SKIP' AS result,CONCAT('Requires 2008+. Current: ',@ver) AS message; RETURN; END;
SELECT @bad=COUNT(*) FROM sys.indexes i JOIN sys.index_columns ic ON i.object_id=ic.object_id AND i.index_id=ic.index_id JOIN sys.columns c ON ic.object_id=c.object_id AND ic.column_id=c.column_id JOIN sys.types t ON c.system_type_id=t.system_type_id WHERE i.object_id>100 AND i.type_desc='CLUSTERED' AND t.name='uniqueidentifier' AND ic.key_ordinal=1;
