SELECT @sys_owned=COUNT(*) FROM sys.endpoints WHERE type_desc IN ('DATABASE_MIRRORING','SERVICE_BROKER') AND principal_id=1;
SELECT CASE WHEN @sys_owned=0 THEN 'PASS' ELSE 'FAIL' END AS result, CASE WHEN @sys_owned=0 THEN 'HA endpoints use dedicated accounts.' ELSE CONCAT(@sys_owned,' endpoint(s) owned by sa. Use dedicated account for endpoint ownership.') END AS message;

DECLARE @ver INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver=CONVERT(INT,SERVERPROPERTY('ProductMajorVersion')); IF @ver<10 BEGIN SELECT 'SKIP' AS result,CONCAT('Requires 2008+. Current: ',@ver) AS message; RETURN; END;
SELECT 'INFO' AS result, 'DBCC events can be extracted from the default trace by reading fn_trace_getdata. Use sys.fn_trace_gettable to query the default trace file for EventClass 116 (DBCC events).' AS message;

DECLARE @ver INT;
DECLARE @bad_services INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 11
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2012 (11.0) or later for service account DMV. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @bad_services = COUNT(*)
FROM sys.dm_server_services
WHERE service_account IN
    ('NT AUTHORITY\SYSTEM', 'NT AUTHORITY\NETWORK SERVICE', 'NT AUTHORITY\LOCAL SERVICE',
     'NT AUTHORITY\NETWORKSERVICE', 'LocalSystem', 'NT AUTHORITY\SYSTEM',
     'NT SERVICE\SQLWriter', 'NT SERVICE\Winmgmt')
   OR service_account LIKE '%\SQLServer%'
   OR service_account LIKE 'NT SERVICE\%';

IF @bad_services = 0
BEGIN
    SET @result = 'PASS';
    SET @msg = 'All SQL Server services use dedicated accounts.';
END
ELSE
BEGIN
    SET @result = 'FAIL';
    SET @msg = CONVERT(VARCHAR, @bad_services) + ' SQL Server service(s) use built-in or potentially shared accounts. Use dedicated domain or gMSA accounts.';
END;

SELECT @result AS result, @msg AS message;

DECLARE @ver INT, @unknown_owner INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver=CONVERT(INT,SERVERPROPERTY('ProductMajorVersion')); IF @ver<10 BEGIN SELECT 'SKIP' AS result,CONCAT('Requires 2008+. Current: ',@ver) AS message; RETURN; END;
SELECT @unknown_owner=COUNT(*) FROM sys.databases WHERE owner_sid IS NOT NULL AND NOT EXISTS (SELECT 1 FROM sys.server_principals WHERE sid=owner_sid) AND database_id>4;
IF @unknown_owner=0 BEGIN SET @result='PASS'; SET @msg='All databases have known owners.'; END
ELSE BEGIN SET @result='FAIL'; SET @msg=CONCAT(@unknown_owner,' database(s) with unknown owners. Use ALTER AUTHORIZATION to set correct owner.'); END
SELECT @result AS result, @msg AS message;

