SELECT @imp_trans=COUNT(*) FROM sys.sql_modules WHERE object_id>100 AND definition LIKE '%SET IMPLICIT_TRANSACTIONS ON%' AND definition NOT LIKE '%SET IMPLICIT_TRANSACTIONS OFF%';
IF @imp_trans=0 BEGIN SET @result='PASS'; SET @msg='No procedures set IMPLICIT_TRANSACTIONS ON.'; END
ELSE BEGIN SET @result='WARN'; SET @msg=CONCAT(@imp_trans,' procedure(s) use IMPLICIT_TRANSACTIONS ON — can cause blocking.'); END
