DECLARE @ver INT;
DECLARE @small_data_files INT;
DECLARE @small_log_files INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

-- Data files smaller than 128 MB are likely default-sized (not proactively sized)
SELECT @small_data_files = COUNT(*)
FROM sys.master_files
WHERE database_id > 4
  AND type_desc = 'ROWS'
  AND size * 8 / 1024 < 128;

-- Log files smaller than 64 MB are likely default-sized
SELECT @small_log_files = COUNT(*)
FROM sys.master_files
WHERE database_id > 4
  AND type_desc = 'LOG'
  AND size * 8 / 1024 < 64;

IF @small_data_files = 0 AND @small_log_files = 0
BEGIN
    SET @result = 'PASS';
    SET @msg = 'All user database files appear to be proactively sized.';
END
ELSE
BEGIN
    SET @msg = '';
    IF @small_data_files > 0
        SET @msg = CONVERT(VARCHAR, @small_data_files) + ' data file(s) under 128 MB. ';
    IF @small_log_files > 0
        SET @msg = @msg + CONVERT(VARCHAR, @small_log_files) + ' log file(s) under 64 MB. ';
    SET @msg = @msg + 'Pre-size files to expected production size to avoid autogrowth stalls.';
    SET @result = 'FAIL';
END;

SELECT @result AS result, @msg AS message;

DECLARE @ver INT;
DECLARE @bad_log_count INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
