-- Log files with percentage growth or very small fixed growth (< 64 MB) produce excessive VLFs
SELECT @bad_log_count = COUNT(*)
FROM sys.master_files
WHERE database_id > 4
  AND type_desc = 'LOG'
  AND (is_percent_growth = 1 OR (is_percent_growth = 0 AND growth * 8 / 1024 < 64));

IF @bad_log_count = 0
BEGIN
    SET @result = 'PASS';
    SET @msg = 'All user database log files use growth settings that limit VLF proliferation.';
END
ELSE
BEGIN
    SET @result = 'FAIL';
    SET @msg = CONVERT(VARCHAR, @bad_log_count) + ' user database log file(s) have settings that cause excessive VLFs. Use fixed MB growth (256 MB+).';
END;

SELECT @result AS result, @msg AS message;

DECLARE @ver INT;
DECLARE @cpu_count INT;
DECLARE @numa_nodes INT;
DECLARE @cpus_per_numa DECIMAL(10,2);
DECLARE @current_maxdop INT;
DECLARE @recommended INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 13
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2016 (13.0) or later for NUMA-aware MAXDOP guidance. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @cpu_count = cpu_count FROM sys.dm_os_sys_info;

SELECT @numa_nodes = COUNT(*) FROM sys.dm_os_nodes WHERE memory_node_id = 0;

SELECT @current_maxdop = CONVERT(INT, value_in_use)
FROM sys.configurations
WHERE name = 'max degree of parallelism';

IF @numa_nodes = 0
BEGIN
    SELECT 'FAIL' AS result, 'Could not determine NUMA node count from sys.dm_os_nodes. CPU count: ' + ISNULL(CONVERT(VARCHAR, @cpu_count), 'unknown') + '. Cannot compute NUMA-aware MAXDOP recommendation.' AS message;
    RETURN;
END;

SET @cpus_per_numa = CONVERT(DECIMAL(10,2), @cpu_count) / CONVERT(DECIMAL(10,2), @numa_nodes);

IF @cpus_per_numa <= 8
    SET @recommended = CONVERT(INT, FLOOR(@cpus_per_numa));
ELSE
    SET @recommended = 8;

IF @recommended < 1 SET @recommended = 1;

IF @current_maxdop = 0
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'MAXDOP is set to 0 (unlimited). Recommended value based on NUMA topology: '
        + CONVERT(VARCHAR, @recommended) + ' (cores per NUMA node: '
        + CONVERT(VARCHAR, CONVERT(INT, @cpus_per_numa)) + ', NUMA nodes: '
        + CONVERT(VARCHAR, @numa_nodes) + ', total CPUs: '
        + CONVERT(VARCHAR, @cpu_count) + ').';
END
ELSE IF @current_maxdop > @recommended + 2
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'MAXDOP is set to ' + CONVERT(VARCHAR, @current_maxdop)
        + ', which exceeds the recommended value of ' + CONVERT(VARCHAR, @recommended)
        + ' (cores per NUMA node: ' + CONVERT(VARCHAR, CONVERT(INT, @cpus_per_numa))
        + ', NUMA nodes: ' + CONVERT(VARCHAR, @numa_nodes)
        + ', total CPUs: ' + CONVERT(VARCHAR, @cpu_count) + ').';
END
ELSE IF @current_maxdop > @recommended
BEGIN
    SET @result = 'WARN';
    SET @msg = 'MAXDOP is set to ' + CONVERT(VARCHAR, @current_maxdop)
        + ', slightly above recommended ' + CONVERT(VARCHAR, @recommended)
        + ' (cores per NUMA node: ' + CONVERT(VARCHAR, CONVERT(INT, @cpus_per_numa))
        + ', NUMA nodes: ' + CONVERT(VARCHAR, @numa_nodes) + '). Review if workload justifies higher DOP.';
END
ELSE
BEGIN
    SET @result = 'PASS';
    SET @msg = 'MAXDOP is set to ' + CONVERT(VARCHAR, @current_maxdop)
        + ', which matches the recommended value of ' + CONVERT(VARCHAR, @recommended)
        + ' (cores per NUMA node: ' + CONVERT(VARCHAR, CONVERT(INT, @cpus_per_numa))
        + ', NUMA nodes: ' + CONVERT(VARCHAR, @numa_nodes)
        + ', total CPUs: ' + CONVERT(VARCHAR, @cpu_count) + ').';
END;

SELECT @result AS result, @msg AS message;

