    SET @msg = CONVERT(VARCHAR, @simple_count) + ' user database(s) use SIMPLE recovery model. '
        + CONVERT(VARCHAR, @full_count) + ' use FULL. Production databases should use FULL for point-in-time recovery.';
END;

