DECLARE @ver INT;
DECLARE @compressed_tables INT;
DECLARE @total_indexes INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @total_indexes = COUNT(*),
       @compressed_tables = SUM(CASE WHEN data_compression_desc IN ('ROW', 'PAGE') THEN 1 ELSE 0 END)
FROM sys.partitions
WHERE object_id > 100;

IF @total_indexes = 0
BEGIN
    SET @result = 'PASS';
    SET @msg = 'No user objects found. Skipping compression check.';
END
ELSE IF @compressed_tables > 0
BEGIN
    SET @result = 'PASS';
    SET @msg = CONVERT(VARCHAR, @compressed_tables) + ' of ' + CONVERT(VARCHAR, @total_indexes) + ' partitions use data compression (ROW or PAGE).';
END
ELSE
BEGIN
    SET @result = 'INFO';
    SET @msg = 'No partitions use data compression. Consider ROW or PAGE compression for large tables to reduce storage and I/O.';
END;

