DECLARE @ver INT;
DECLARE @unused_indexes INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @unused_indexes = COUNT(*)
FROM sys.indexes i
WHERE i.object_id > 100
  AND i.index_id > 0
  AND i.is_disabled = 0
  AND i.is_hypothetical = 0
  AND NOT EXISTS (
      SELECT 1
      FROM sys.dm_db_index_usage_stats ius
      WHERE ius.object_id = i.object_id
        AND ius.index_id = i.index_id
        AND ius.database_id = DB_ID()
        AND (ius.user_seeks + ius.user_scans + ius.user_lookups) > 0
  );

IF @unused_indexes = 0
BEGIN
    SET @result = 'PASS';
    SET @msg = 'No unused indexes detected in current database context.';
END
ELSE
BEGIN
    SET @result = 'WARN';
    SET @msg = CONVERT(VARCHAR, @unused_indexes) + ' index(es) have zero seeks/scans/lookups. Review and consider removing to save write overhead and storage.';
END;

