DECLARE @ver INT;
DECLARE @current_ctfp INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @current_ctfp = CONVERT(INT, value_in_use)
FROM sys.configurations
WHERE name = 'cost threshold for parallelism';

IF @current_ctfp = 5
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'Cost Threshold for Parallelism is set to the default value of 5 (from SQL Server 7.0). '
        + 'This is far too low for modern hardware. Recommended: 50 for typical OLTP workloads.';
END
ELSE IF @current_ctfp = 0
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'Cost Threshold for Parallelism is set to 0 (disabled). '
        + 'This allows all queries to be candidates for parallel execution, '
        + 'which can cause excessive parallelism. Recommended: 50.';
END
ELSE IF @current_ctfp < 25
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'Cost Threshold for Parallelism is set to ' + CONVERT(VARCHAR, @current_ctfp)
        + ', which is below the recommended minimum of 25. Recommended: 50.';
END
ELSE IF @current_ctfp >= 25 AND @current_ctfp < 50
BEGIN
    SET @result = 'WARN';
    SET @msg = 'Cost Threshold for Parallelism is set to ' + CONVERT(VARCHAR, @current_ctfp)
        + ', within acceptable range (25-50) but below the optimal value of 50.';
END
ELSE IF @current_ctfp = 50
BEGIN
    SET @result = 'PASS';
    SET @msg = 'Cost Threshold for Parallelism is set to 50, the recommended starting point for modern OLTP systems.';
END
ELSE IF @current_ctfp > 50 AND @current_ctfp <= 100
BEGIN
    SET @result = 'WARN';
    SET @msg = 'Cost Threshold for Parallelism is set to ' + CONVERT(VARCHAR, @current_ctfp)
        + ', which is above the standard recommendation of 50. '
        + 'Acceptable if workload is reporting-heavy. Verify CXPACKET waits are acceptable.';
END
ELSE
BEGIN
    SET @result = 'WARN';
    SET @msg = 'Cost Threshold for Parallelism is set to ' + CONVERT(VARCHAR, @current_ctfp)
        + ', which exceeds 100. Verify this high value is intentional for your workload.';
END;

SELECT @result AS result, @msg AS message;

