DECLARE @ver INT;
DECLARE @over_indexed_tables INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @over_indexed_tables = COUNT(*)
FROM (
    SELECT i.object_id
    FROM sys.indexes i
    JOIN sys.objects o ON i.object_id = o.object_id
    WHERE o.is_ms_shipped = 0
      AND o.type = 'U'
      AND i.index_id > 1
      AND i.is_disabled = 0
    GROUP BY i.object_id
    HAVING COUNT(*) > 5
) over_indexed;

IF @over_indexed_tables = 0
BEGIN
    SET @result = 'PASS';
    SET @msg = 'No tables have excessive indexes (more than 5 non-clustered).';
END
ELSE
BEGIN
    SET @result = 'WARN';
    SET @msg = CONVERT(VARCHAR, @over_indexed_tables) + ' table(s) have more than 5 non-clustered indexes. Review for redundancy and write-performance impact.';
END;

SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @nonclustered INT; DECLARE @with_include INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message; RETURN; END;
SELECT @nonclustered = COUNT(*) FROM sys.indexes WHERE object_id > 100 AND index_id > 1 AND index_id < 255;
SELECT @with_include = COUNT(DISTINCT i.object_id) FROM sys.indexes i JOIN sys.index_columns ic ON i.object_id = ic.object_id AND i.index_id = ic.index_id WHERE i.object_id > 100 AND i.index_id > 1 AND i.index_id < 255 AND ic.is_included_column = 1;
IF @nonclustered = 0 BEGIN SET @result = 'PASS'; SET @msg = 'No non-clustered indexes found on user tables.'; END
ELSE IF @with_include > 0 BEGIN SET @result = 'PASS'; SET @msg = CONVERT(VARCHAR, @with_include) + ' table(s) have covering indexes using INCLUDE columns.'; END
ELSE BEGIN SET @result = 'WARN'; SET @msg = CONVERT(VARCHAR, @nonclustered) + ' non-clustered index(es) exist but none use INCLUDE columns. Consider adding INCLUDE columns for covering index benefits.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT, @alerts INT, @dbmail INT, @operators INT, @result VARCHAR(10), @msg NVARCHAR(1000);
