SELECT @alerts=COUNT(*) FROM msdb.dbo.sysalerts WHERE enabled=1;
SELECT @dbmail=CONVERT(INT,value_in_use) FROM sys.configurations WHERE name='Database Mail XPs';
SELECT @operators=COUNT(*) FROM msdb.dbo.sysoperators;
IF @alerts>0 AND @operators>0 BEGIN SET @result='PASS'; SET @msg=CONCAT(@alerts,' alerts, ',@operators,' operators configured.'); END
ELSE BEGIN SET @result='FAIL'; SET @msg=CONCAT(@alerts,' alerts, ',@operators,' operators. Configure alerts and operators for event notification.'); END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT, @sev16 INT, @result VARCHAR(10), @msg NVARCHAR(1000);
