SELECT @not_exists = COUNT(*) FROM sys.databases WHERE database_id > 4 AND is_query_store_on = 0;
IF @not_exists > 0 BEGIN SET @result = 'FAIL'; SET @msg = CONVERT(VARCHAR, @not_exists) + ' database(s) must have Query Store enabled before FORCE_LAST_GOOD_PLAN can work. Enable Query Store first (see check_44).'; SELECT @result AS result, @msg AS message; RETURN; END;
