ELSE IF @maxdop>@rec_maxdop+2 BEGIN SET @result='FAIL'; SET @msg=CONCAT('MAXDOP=',@maxdop,' > recommended ',@rec_maxdop,' for ',@cpu_count,' CPUs.'); END
ELSE BEGIN SET @result='PASS'; SET @msg=CONCAT('MAXDOP=',@maxdop,' within range (recommended: ',@rec_maxdop,').'); END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @psp_enabled INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 16 BEGIN SELECT 'SKIP' AS result, 'Parameter Sensitive Plan Optimization requires SQL Server 2022 (16.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message; RETURN; END;
SELECT @psp_enabled = COUNT(*) FROM sys.database_scoped_configurations WHERE name = 'PARAMETER_SENSITIVE_PLAN_OPTIMIZATION' AND value = 1;
IF @psp_enabled > 0 BEGIN SET @result = 'PASS'; SET @msg = CONVERT(VARCHAR, @psp_enabled) + ' database(s) have PSP optimization enabled.'; END
ELSE BEGIN SET @result = 'WARN'; SET @msg = 'PSP database scoped configuration not found or not enabled. Enable for databases with parameter-sniffing issues.'; END
