DECLARE @ver INT;
DECLARE @min_mb BIGINT;
DECLARE @max_mb BIGINT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

-- Get current min and max server memory
SELECT @min_mb = CONVERT(BIGINT, MAX(CASE WHEN name = 'min server memory (MB)' THEN value_in_use ELSE 0 END)),
       @max_mb = CONVERT(BIGINT, MAX(CASE WHEN name = 'max server memory (MB)' THEN value_in_use ELSE 0 END))
FROM sys.configurations
WHERE name IN ('min server memory (MB)', 'max server memory (MB)');

-- Evaluate
IF @min_mb >= @max_mb
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'Min server memory (' + CONVERT(VARCHAR, @min_mb) + ' MB) is >= max server memory ('
        + CONVERT(VARCHAR, @max_mb) + ' MB). This can prevent SQL Server from starting '
        + 'or cause severe performance degradation.';
END
ELSE IF @min_mb > 0 AND @min_mb < 128
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'Min server memory is set to ' + CONVERT(VARCHAR, @min_mb)
        + ' MB, which is too low to be effective (minimum practical value is 128 MB). '
        + 'Recommended: set min server memory to 0 (default).';
END
ELSE IF @min_mb > 0
BEGIN
    SET @result = 'WARN';
    SET @msg = 'Min server memory is set to ' + CONVERT(VARCHAR, @min_mb)
        + ' MB (max: ' + CONVERT(VARCHAR, @max_mb) + ' MB). '
        + 'Microsoft recommends 0. Document the operational reason for this non-zero minimum.';
END
ELSE
BEGIN
    SET @result = 'PASS';
    SET @msg = 'Min server memory is 0 MB (Microsoft-recommended default). '
        + 'Max server memory: ' + CONVERT(VARCHAR, @max_mb) + ' MB.';
END;

SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @proc_count INT; DECLARE @select_star INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message; RETURN; END;
SELECT @proc_count = COUNT(*) FROM sys.sql_modules WHERE object_id > 100;
SELECT @select_star = COUNT(*) FROM sys.sql_modules WHERE object_id > 100 AND definition LIKE '%SELECT *%';
IF @select_star = 0 BEGIN SET @result = 'PASS'; SET @msg = 'No user stored procedures use SELECT *.'; END
ELSE BEGIN SET @result = 'WARN'; SET @msg = CONVERT(VARCHAR, @select_star) + ' of ' + CONVERT(VARCHAR, @proc_count) + ' module(s) contain SELECT *. Review and replace with explicit column lists.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @total_procs INT; DECLARE @without_nocount INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message; RETURN; END;
SELECT @total_procs = COUNT(*) FROM sys.sql_modules m JOIN sys.objects o ON m.object_id = o.object_id WHERE o.type IN ('P', 'FN', 'IF', 'TF') AND o.object_id > 100;
SELECT @without_nocount = COUNT(*) FROM sys.sql_modules m JOIN sys.objects o ON m.object_id = o.object_id WHERE o.type IN ('P', 'FN', 'IF', 'TF') AND o.object_id > 100 AND m.definition NOT LIKE '%SET NOCOUNT ON%';
IF @without_nocount = 0 BEGIN SET @result = 'PASS'; SET @msg = 'All user procedures include SET NOCOUNT ON.'; END
ELSE BEGIN SET @result = 'WARN'; SET @msg = CONVERT(VARCHAR, @without_nocount) + ' of ' + CONVERT(VARCHAR, @total_procs) + ' procedure(s) do not include SET NOCOUNT ON.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @rls_tables INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 13 BEGIN SELECT 'SKIP' AS result,'RLS requires SQL Server 2016 (13.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT @rls_tables = COUNT(DISTINCT object_id) FROM sys.security_predicates;
IF @rls_tables > 0 BEGIN SET @result = 'PASS'; SET @msg = CONVERT(VARCHAR,@rls_tables)+' table(s) have RLS predicates defined.'; END
ELSE BEGIN SET @result = 'INFO'; SET @msg = 'No RLS predicates found. Apply RLS for multi-tenant workloads requiring row-level data isolation.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT, @low_space INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver=CONVERT(INT,SERVERPROPERTY('ProductMajorVersion')); IF @ver<10 BEGIN SELECT 'SKIP' AS result,CONCAT('Requires 2008+. Current: ',@ver) AS message; RETURN; END;
SELECT @low_space=COUNT(*) FROM (SELECT DISTINCT database_id, file_id FROM sys.master_files WHERE database_id>4) f CROSS APPLY sys.dm_os_volume_stats(f.database_id, f.file_id) s WHERE s.available_bytes*1.0/s.total_bytes<0.1;
SELECT CASE WHEN @low_space=0 THEN 'PASS' ELSE 'FAIL' END AS result, CASE WHEN @low_space=0 THEN 'All drives have >10% free space.' ELSE CONCAT(@low_space,' database file(s) on drives with <10% free space. Add storage immediately.') END AS message;

DECLARE @ver INT, @slow_drives INT, @max_lat_ms DECIMAL(10,2), @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, CONCAT('Requires 2008+. Current: ', @ver) AS message;
    RETURN;
END;
SELECT @slow_drives = COUNT(*), @max_lat_ms = ISNULL(MAX(avg_read),0)
FROM (
    SELECT LEFT(mf.physical_name, 1) AS drive,
           AVG(CAST(vfs.io_stall_read_ms AS FLOAT) / NULLIF(vfs.num_of_reads, 0)) AS avg_read
    FROM sys.dm_io_virtual_file_stats(NULL, NULL) vfs
    JOIN sys.master_files mf ON vfs.database_id = mf.database_id AND vfs.file_id = mf.file_id
    WHERE vfs.num_of_reads > 1000
    GROUP BY LEFT(mf.physical_name, 1)
) drives
WHERE avg_read > 15;
IF @slow_drives = 0
BEGIN
    SET @result = 'PASS';
    SET @msg = CONCAT('No drives exceed 15ms avg read latency. Max observed: ', CONVERT(VARCHAR, CONVERT(INT, @max_lat_ms)), 'ms. Storage subsystem is performing well.');
END
ELSE
BEGIN
    SET @result = 'WARN';
    SET @msg = CONCAT(@slow_drives, ' drive(s) exceed 15ms avg read latency (max: ', CONVERT(VARCHAR, CONVERT(INT, @max_lat_ms)), 'ms). Consider migrating database files to premium SSDs for consistent sub-10ms latency.');
END;
SELECT @result AS result, @msg AS message;

DECLARE @ver INT, @lpin INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver=CONVERT(INT,SERVERPROPERTY('ProductMajorVersion')); IF @ver<10 BEGIN SELECT 'SKIP' AS result,CONCAT('Requires 2008+. Current: ',@ver) AS message; RETURN; END;
SELECT @lpin=CONVERT(INT,value_in_use) FROM sys.configurations WHERE name='locking pages in memory';
SELECT CASE WHEN @lpin=1 THEN 'PASS' ELSE 'WARN' END AS result, CASE WHEN @lpin=1 THEN 'Lock pages in memory is enabled.' ELSE 'Lock pages in memory is disabled. Enable for large-memory SQL Server instances to prevent OS paging.' END AS message;

DECLARE @ver INT; DECLARE @contained_count INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 11 BEGIN SELECT 'SKIP' AS result,'Contained databases require SQL Server 2012 (11.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT @contained_count = COUNT(*) FROM sys.databases WHERE containment_desc <> 'NONE' AND database_id > 4;
IF @contained_count > 0 BEGIN SET @result = 'PASS'; SET @msg = CONVERT(VARCHAR,@contained_count)+' contained database(s) found.'; END
ELSE BEGIN SET @result = 'INFO'; SET @msg = 'No contained databases found. Evaluate for multi-instance or migration scenarios.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @orphaned INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result,'Requires SQL Server 2008 (10.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT @orphaned = COUNT(*) FROM sys.database_principals dp WHERE dp.type IN ('U','S') AND dp.authentication_type_desc = 'INSTANCE' AND dp.principal_id > 4 AND NOT EXISTS (SELECT 1 FROM sys.server_principals sp WHERE sp.name = dp.name);
IF @orphaned = 0 BEGIN SET @result = 'PASS'; SET @msg = 'No orphaned database users found in master.'; END
ELSE BEGIN SET @result = 'FAIL'; SET @msg = CONVERT(VARCHAR,@orphaned)+' orphaned user(s) found in master. Use sp_change_users_login to fix.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT;
DECLARE @enabled INT;
DECLARE @single_use_mb DECIMAL(18,2);
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @enabled = CONVERT(INT, value_in_use)
FROM sys.configurations
WHERE name = 'optimize for ad hoc workloads';

SELECT @single_use_mb = CONVERT(DECIMAL(18,2),
    ISNULL(SUM(CONVERT(BIGINT, size_in_bytes)), 0) / 1048576.0)
FROM sys.dm_exec_cached_plans
WHERE objtype = 'Adhoc'
  AND usecounts = 1;

IF @enabled = 1
BEGIN
    SET @result = 'PASS';
    SET @msg = 'Optimize for ad hoc workloads is enabled (1). '
        + 'Current single-use ad hoc plan memory: '
        + CONVERT(VARCHAR, CONVERT(INT, @single_use_mb)) + ' MB.';
END
ELSE
BEGIN
    IF @single_use_mb > 200
    BEGIN
        SET @result = 'FAIL';
        SET @msg = 'Optimize for ad hoc workloads is disabled (0). '
            + 'Single-use ad hoc plans consume '
            + CONVERT(VARCHAR, CONVERT(INT, @single_use_mb))
            + ' MB of plan cache. Enable this option to reduce memory pressure.';
    END
    ELSE IF @single_use_mb > 50
    BEGIN
        SET @result = 'WARN';
        SET @msg = 'Optimize for ad hoc workloads is disabled (0). '
            + 'Single-use ad hoc plans consume '
            + CONVERT(VARCHAR, CONVERT(INT, @single_use_mb))
            + ' MB. Consider enabling to reduce plan cache memory.';
    END
    ELSE
    BEGIN
        SET @result = 'FAIL';
        SET @msg = 'Optimize for ad hoc workloads is disabled (0). '
            + 'Single-use ad hoc plan memory: '
            + CONVERT(VARCHAR, CONVERT(INT, @single_use_mb))
            + ' MB. Enable for best practice configuration.';
    END;
END;

SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @classified_cols INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 15 BEGIN SELECT 'SKIP' AS result,'Data Classification requires SQL Server 2019 (15.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT @classified_cols = COUNT(*) FROM sys.sensitivity_classifications;
IF @classified_cols > 0 BEGIN SET @result = 'PASS'; SET @msg = CONVERT(VARCHAR,@classified_cols)+' column(s) have sensitivity classifications.'; END
ELSE BEGIN SET @result = 'INFO'; SET @msg = 'No sensitivity classifications found. Classify sensitive columns for compliance labeling.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @full_no_log INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result,'Requires SQL Server 2008 (10.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT @full_no_log = COUNT(*) FROM sys.databases d WHERE d.database_id > 4 AND d.recovery_model_desc = 'FULL' AND NOT EXISTS (SELECT 1 FROM msdb.dbo.backupset b WHERE b.database_name = d.name AND b.type = 'L' AND b.backup_finish_date > DATEADD(HOUR,-24,GETDATE()));
IF @full_no_log = 0 BEGIN SET @result = 'PASS'; SET @msg = 'All FULL recovery databases have had log backups in the last 24 hours.'; END
ELSE BEGIN SET @result = 'FAIL'; SET @msg = CONVERT(VARCHAR,@full_no_log)+' FULL recovery database(s) have no log backups in 24h. Risk of log file growth and data loss.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @uncompressed INT; DECLARE @total INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result,'Requires SQL Server 2008 (10.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT @total = COUNT(*), @uncompressed = SUM(CASE WHEN compressed_backup_size IS NULL THEN 1 ELSE 0 END) FROM msdb.dbo.backupset WHERE backup_finish_date > DATEADD(DAY,-30,GETDATE());
IF @total = 0 BEGIN SET @result = 'INFO'; SET @msg = 'No backups found in last 30 days.'; END
ELSE IF @uncompressed = 0 BEGIN SET @result = 'PASS'; SET @msg = 'All '+CONVERT(VARCHAR,@total)+' recent backup(s) are compressed.'; END
ELSE BEGIN SET @result = 'FAIL'; SET @msg = CONVERT(VARCHAR,@uncompressed)+' of '+CONVERT(VARCHAR,@total)+' recent backup(s) are uncompressed. Enable compression.'; END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT; DECLARE @non_copy INT; DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
