IF @ver < 10 BEGIN SELECT 'SKIP' AS result,'Requires SQL Server 2008 (10.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT @non_copy = COUNT(*) FROM msdb.dbo.backupset WHERE backup_finish_date > DATEADD(DAY,-30,GETDATE()) AND is_copy_only = 0 AND type = 'D';
IF @non_copy > 0 BEGIN SET @result = 'INFO'; SET @msg = CONVERT(VARCHAR,@non_copy)+' full database backup(s) in last 30 days. Ad-hoc backups should use COPY_ONLY to avoid breaking the LSN chain.'; END
ELSE BEGIN SET @result = 'INFO'; SET @msg = 'No full database backups in the last 30 days.'; END
SELECT @result AS result, @msg AS message;

