IF @verified_count > 0 BEGIN SET @result = 'PASS'; SET @msg = CONVERT(VARCHAR,@verified_count)+' database(s) have been restored or verified in the last 90 days.'; END
ELSE BEGIN SET @result = 'FAIL'; SET @msg = 'No databases have been restored or verified in the last 90 days. Regular restore verification is critical for disaster recovery readiness.'; END
