IF @ver < 10 BEGIN SELECT 'SKIP' AS result,'Requires SQL Server 2008 (10.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT TOP 1 @data_drive = LEFT(physical_name,1) FROM sys.master_files WHERE database_id > 4 AND type_desc = 'ROWS';
SELECT TOP 1 @backup_drive = LEFT(physical_device_name,1) FROM msdb.dbo.backupmediafamily WHERE physical_device_name LIKE '%:%';
IF @data_drive IS NULL OR @backup_drive IS NULL BEGIN SET @result = 'INFO'; SET @msg = 'Could not determine data/backup drive separation.'; END
ELSE IF @data_drive <> @backup_drive BEGIN SET @result = 'PASS'; SET @msg = 'Database files are on drive ' + @data_drive + ', backups are on drive ' + @backup_drive + '. Proper separation.'; END
ELSE BEGIN SET @result = 'WARN'; SET @msg = 'Database files and backups are both on drive ' + @data_drive + '. Store backups on separate physical storage.'; END
SELECT @result AS result, @msg AS message;

