DECLARE @ver INT;
DECLARE @enabled INT;
DECLARE @uncompressed_backups INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @enabled = CONVERT(INT, value_in_use)
FROM sys.configurations
WHERE name = 'backup compression default';

SELECT @uncompressed_backups = COUNT(*)
FROM msdb.dbo.backupset
WHERE backup_finish_date > DATEADD(DAY, -30, GETDATE())
  AND compressed_backup_size IS NULL;

IF @enabled = 1
BEGIN
    SET @result = 'PASS';
    SET @msg = 'Backup compression default is enabled (1). ';
    IF @uncompressed_backups > 0
        SET @msg = @msg + CONVERT(VARCHAR, @uncompressed_backups)
            + ' uncompressed backup(s) found in the last 30 days '
            + '(may be from jobs specifying no compression explicitly).';
    ELSE
        SET @msg = @msg + 'No uncompressed backups found in the last 30 days.';
END
ELSE
BEGIN
    IF @uncompressed_backups > 0
    BEGIN
        SET @result = 'FAIL';
        SET @msg = 'Backup compression default is disabled (0). '
            + CONVERT(VARCHAR, @uncompressed_backups)
            + ' uncompressed backup(s) found in the last 30 days. '
            + 'Enable to save 60-80% storage and improve I/O performance.';
    END
    ELSE
    BEGIN
        SET @result = 'INFO';
        SET @msg = 'Backup compression default is disabled (0), '
            + 'but no uncompressed backups found in the last 30 days. '
            + 'Enable proactively for future storage and I/O efficiency.';
    END;
END;

SELECT @result AS result, @msg AS message;

