DECLARE @ver INT; DECLARE @top_wait_ms BIGINT; DECLARE @top_wait_type NVARCHAR(60); DECLARE @result VARCHAR(10); DECLARE @msg NVARCHAR(1000);
SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));
IF @ver < 10 BEGIN SELECT 'SKIP' AS result,'Requires SQL Server 2008 (10.0) or later. Current major version: '+ISNULL(CONVERT(VARCHAR,@ver),'unknown')+'.' AS message; RETURN; END;
SELECT TOP 1 @top_wait_type = wait_type, @top_wait_ms = wait_time_ms FROM sys.dm_os_wait_stats WHERE wait_type NOT IN ('BROKER_EVENT_HANDLER','BROKER_RECEIVE_WAITFOR','SLEEP_TASK','REQUEST_FOR_DEADLOCK_SEARCH','SQLTRACE_INCREMENTAL_FLUSH_SLEEP','SQLTRACE_WAIT_ENTRIES','XE_DISPATCHER_WAIT','XE_TIMER_EVENT','WAITFOR') ORDER BY wait_time_ms DESC;
SET @result = 'INFO'; SET @msg = 'Top wait type: '+@top_wait_type+' ('+CONVERT(VARCHAR,CONVERT(DECIMAL(18,1),@top_wait_ms/1000.0))+' sec). Query sys.dm_os_wait_stats for detailed wait analysis.';
SELECT @result AS result, @msg AS message;

