DECLARE @ver INT;
DECLARE @data_drives INT;
DECLARE @log_drives INT;
DECLARE @tempdb_drives INT;
DECLARE @total_categories INT;
DECLARE @result VARCHAR(10);
DECLARE @msg NVARCHAR(1000);

SET @ver = CONVERT(INT, SERVERPROPERTY('ProductMajorVersion'));

IF @ver < 10
BEGIN
    SELECT 'SKIP' AS result, 'Requires SQL Server 2008 (10.0) or later. Current major version: ' + ISNULL(CONVERT(VARCHAR, @ver), 'unknown') + '.' AS message;
    RETURN;
END;

SELECT @data_drives = COUNT(DISTINCT LEFT(physical_name, 1))
FROM sys.master_files
WHERE database_id > 4 AND type_desc = 'ROWS';

SELECT @log_drives = COUNT(DISTINCT LEFT(physical_name, 1))
FROM sys.master_files
WHERE database_id > 4 AND type_desc = 'LOG';

SELECT @tempdb_drives = COUNT(DISTINCT LEFT(physical_name, 1))
FROM sys.master_files
WHERE database_id = 2;

SET @total_categories = CASE WHEN @data_drives > 0 THEN 1 ELSE 0 END
                     + CASE WHEN @log_drives > 0 THEN 1 ELSE 0 END
                     + CASE WHEN @tempdb_drives > 0 THEN 1 ELSE 0 END;

IF @data_drives >= 1 AND @log_drives >= 1 AND @tempdb_drives >= 1
   AND @data_drives + @log_drives + @tempdb_drives >= 3
BEGIN
    SET @result = 'PASS';
    SET @msg = 'Data, log, and TempDB files are on dedicated drives. Data: '
        + CONVERT(VARCHAR, @data_drives) + ' drive(s). Log: '
        + CONVERT(VARCHAR, @log_drives) + ' drive(s). TempDB: '
        + CONVERT(VARCHAR, @tempdb_drives) + ' drive(s).';
END
ELSE IF @data_drives + @log_drives + @tempdb_drives >= 2
BEGIN
    SET @result = 'WARN';
    SET @msg = 'Partial file separation. Data: ' + CONVERT(VARCHAR, @data_drives)
        + ' drive(s). Log: ' + CONVERT(VARCHAR, @log_drives) + ' drive(s). TempDB: '
        + CONVERT(VARCHAR, @tempdb_drives) + ' drive(s). '
        + 'Separate log and TempDB to dedicated drives for optimal performance.';
END
ELSE
BEGIN
    SET @result = 'FAIL';
    SET @msg = 'All files share a single drive. Data: ' + CONVERT(VARCHAR, @data_drives)
        + ' drive(s). Log: ' + CONVERT(VARCHAR, @log_drives) + ' drive(s). TempDB: '
        + CONVERT(VARCHAR, @tempdb_drives) + ' drive(s). '
        + 'Move log and TempDB to dedicated drives immediately.';
END;

SELECT @result AS result, @msg AS message;

DECLARE @ver INT, @nondefault INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver=CONVERT(INT,SERVERPROPERTY('ProductMajorVersion')); IF @ver<10 BEGIN SELECT 'SKIP' AS result,CONCAT('Requires 2008+. Current: ',@ver) AS message; RETURN; END;
SELECT @nondefault=COUNT(*) FROM sys.configurations WHERE value_in_use<>0 AND name NOT IN ('max server memory (MB)','min server memory (MB)');
IF @nondefault=0 BEGIN SET @result='PASS'; SET @msg='All configurations at default.'; END
ELSE BEGIN SET @result='INFO'; SET @msg=CONCAT(@nondefault,' non-default configuration(s). Review for necessity.'); END
SELECT @result AS result, @msg AS message;

DECLARE @ver INT, @nd INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver=CONVERT(INT,SERVERPROPERTY('ProductMajorVersion')); IF @ver<10 BEGIN SELECT 'SKIP' AS result,CONCAT('Requires 2008+. Current: ',@ver) AS message; RETURN; END;
