SELECT 'INFO' AS result, 'SPN check cannot be fully validated from T-SQL. Verify SPNs using setspn -L <service_account> on the domain controller.' AS message;

DECLARE @ver INT, @ag_count INT, @db_count INT, @result VARCHAR(10), @msg NVARCHAR(1000);
SET @ver=CONVERT(INT,SERVERPROPERTY('ProductMajorVersion')); IF @ver<11 BEGIN SELECT 'SKIP' AS result,CONCAT('Requires 2012+. Current: ',@ver) AS message; RETURN; END;
SELECT @ag_count=COUNT(*) FROM sys.availability_groups;
SELECT @db_count=COUNT(*) FROM sys.availability_databases_cluster;
IF @ag_count=0 BEGIN SET @result='INFO'; SET @msg='No AGs configured.'; END
ELSE BEGIN SET @result='INFO'; SET @msg=CONCAT(@ag_count,' AG(s) containing ',@db_count,' database(s) total.'); END
SELECT @result AS result, @msg AS message;
